import{_ as r,o as e,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"光通訊追蹤日誌 — 2026-06-17（TST 05:00）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-17.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-17.md"}'),n={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-17.md"};function h(l,a,i,d,s,c){return e(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="光通訊追蹤日誌-—-2026-06-17-tst-05-00" tabindex="-1">光通訊追蹤日誌 — 2026-06-17（TST 05:00） <a class="header-anchor" href="#光通訊追蹤日誌-—-2026-06-17-tst-05-00" aria-label="Permalink to &quot;光通訊追蹤日誌 — 2026-06-17（TST 05:00）&quot;">​</a></h1><h2 id="本日敘事錨點" tabindex="-1">本日敘事錨點 <a class="header-anchor" href="#本日敘事錨點" aria-label="Permalink to &quot;本日敘事錨點&quot;">​</a></h2><p><strong>核心事件：TrendForce 預估 CPO/NPO 市場 2030 年突破 390 億美元，產業結構性需求信號持續偏強。</strong></p><p>今天的全球新聞焦點是美伊 MOU 與央行週，但光通訊產業面出現重要進展：</p><ol><li><strong>TrendForce 最新報告</strong>：CPO/NPO 市場將從 2025 年的 1 億美元爆發成長至 2030 年的 390 億美元以上</li><li><strong>摩根大通報告</strong>：CPO 延遲疑慮過度反應，光通訊類股出現具吸引力的進場點</li><li><strong>中國光通訊供應鏈持續搶佔市占</strong>：中美脫鉤下，中國供應鏈成為台灣不可忽視的競爭者</li><li><strong>InP 出口管制問題</strong>：中國對磷化銦（InP）實施出口管制，Coherent 等大廠發出供應短缺警告</li></ol><p>簡單說，今天不是「光通訊新品日」，而是「產業結構性成長信號再度確認」的一天。</p><p>查詢時間：2026-06-17 05:00 TST（UTC+8）。</p><hr><h2 id="即時指標-4-項" tabindex="-1">即時指標（4 項） <a class="header-anchor" href="#即時指標-4-項" aria-label="Permalink to &quot;即時指標（4 項）&quot;">​</a></h2><h3 id="_1-輝達-gpu-光互連相關" tabindex="-1">1. 輝達 GPU / 光互連相關 <a class="header-anchor" href="#_1-輝達-gpu-光互連相關" aria-label="Permalink to &quot;1. 輝達 GPU / 光互連相關&quot;">​</a></h3><p>今日無新的 CPO / Silicon Photonics 產品公告。<br> 但 TrendForce 報告指出，隨著 AI 訓練與推論需求快速擴張，互連架構已成決定 AI Factory 擴張速度的關鍵戰略資產。<br> 來源：TechNews (2026-06-15)、TrendForce (2026-06-15)</p><h3 id="_2-博通-cpo-光網路動態" tabindex="-1">2. 博通 CPO / 光網路動態 <a class="header-anchor" href="#_2-博通-cpo-光網路動態" aria-label="Permalink to &quot;2. 博通 CPO / 光網路動態&quot;">​</a></h3><p>今日未取得 Taurus / CPO 新公告。<br> 但 TrendForce 指出 Broadcom 為 EML 與 CW-DFB LD 晶片供應商前三大（市占率 55%），為光通訊上游關鍵供應商。<br> 來源：TechNews (2026-06-03)、TrendForce (2026-06-03)</p><h3 id="_3-台積電先進封裝-光通訊相關" tabindex="-1">3. 台積電先進封裝 / 光通訊相關 <a class="header-anchor" href="#_3-台積電先進封裝-光通訊相關" aria-label="Permalink to &quot;3. 台積電先進封裝 / 光通訊相關&quot;">​</a></h3><p>今日無 COUPE / CoWoS 新公告。<br> 但台積電仍維持強勁營收與 AI 封裝需求結構。<br> 來源：TechNews (2026-06-10)</p><h3 id="_4-csp-資本支出" tabindex="-1">4. CSP 資本支出 <a class="header-anchor" href="#_4-csp-資本支出" aria-label="Permalink to &quot;4. CSP 資本支出&quot;">​</a></h3><p>本週最大產業訊號之一：TrendForce 預估 CPO/NPO 市場 2030 年突破 390 億美元。<br> 代表 AI 資本支出不是放緩，而是持續加速，光通訊是其中核心受益者。<br> 來源：TechNews (2026-06-15)、TrendForce (2026-06-15)</p><hr><h2 id="台灣供應鏈列表" tabindex="-1">台灣供應鏈列表 <a class="header-anchor" href="#台灣供應鏈列表" aria-label="Permalink to &quot;台灣供應鏈列表&quot;">​</a></h2><h3 id="聯亞-3081" tabindex="-1">聯亞 (3081) <a class="header-anchor" href="#聯亞-3081" aria-label="Permalink to &quot;聯亞 (3081)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="光聖-6442" tabindex="-1">光聖 (6442) <a class="header-anchor" href="#光聖-6442" aria-label="Permalink to &quot;光聖 (6442)&quot;">​</a></h3><p>本日無法說會或新公告。但近期（5/26）股東會表示：13,824 高芯數產品下半年開始有小量營收貢獻，明後年逐步放量。FAU 產品已送樣美系大廠認證，預計 H2 小量試產。<br> 來源：TechNews (2026-05-26)</p><h3 id="上詮-3363" tabindex="-1">上詮 (3363) <a class="header-anchor" href="#上詮-3363" aria-label="Permalink to &quot;上詮 (3363)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="智邦-2345" tabindex="-1">智邦 (2345) <a class="header-anchor" href="#智邦-2345" aria-label="Permalink to &quot;智邦 (2345)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="其他台灣相關" tabindex="-1">其他台灣相關 <a class="header-anchor" href="#其他台灣相關" aria-label="Permalink to &quot;其他台灣相關&quot;">​</a></h3><ul><li><strong>義隆電 (2458)</strong>：宣布攜手美商 PETA Optronics 進軍光通訊晶片市場，跨足矽光子半導體領域。<br> 來源：TechNews (2026-06-08)</li><li><strong>大立光 (3008)</strong>：股東會上澄清 CPO 產線不需要 4 萬人，FA 自動化產線預計 9 月完成。<br> 來源：TechNews (2026-06-13)</li></ul><hr><h2 id="產業趨勢摘要表" tabindex="-1">產業趨勢摘要表 <a class="header-anchor" href="#產業趨勢摘要表" aria-label="Permalink to &quot;產業趨勢摘要表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>今日狀態</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 維持：TrendForce 確認 AI 流量持續推升光纖需求</td></tr><tr><td>2026 商轉元年</td><td>🟡 觀察：CPO 延遲疑慮被摩根大通認為過度反應</td></tr><tr><td>OCI-MSA / CPO</td><td>🟢 重要進展：TrendForce 預估 2030 年 CPO/NPO 市場突破 390 億美元</td></tr><tr><td>中國供應鏈競爭</td><td>🟡 觀察：中國光通訊供應鏈持續搶佔市占，InP 出口管制成新變數</td></tr></tbody></table><hr><h2 id="今日觀察" tabindex="-1">今日觀察 <a class="header-anchor" href="#今日觀察" aria-label="Permalink to &quot;今日觀察&quot;">​</a></h2><p>今天如果只看「個股公告」，會覺得光通訊很安靜。<br> 但如果看「產業報告」與「結構性成長信號」，其實訊號很強：</p><ol><li><strong>TrendForce 確認 CPO/NPO 2030 年 390 億美元市場</strong>：從 2025 年 1 億美元爆發成長，代表這不是短期題材，而是長期結構性趨勢</li><li><strong>摩根大通認為 CPO 延遲疑慮過度反應</strong>：光通訊類股出現具吸引力的進場點</li><li><strong>InP 出口管制成為新變數</strong>：中國對磷化銦實施出口管制，可能影響全球光通訊供應鏈</li><li><strong>台灣供應鏈持續布局</strong>：光聖 FAU 送樣美系大廠、義隆電跨足光通訊晶片</li></ol><p>後續要觀察的不再是「會不會有需求」，而是「誰先量產、誰先通過客戶驗證、誰能避開 InP 供應風險」。</p><p>查詢時間：2026-06-17 05:00 TST。</p><hr><h2 id="延續昨日敘事" tabindex="-1">延續昨日敘事 <a class="header-anchor" href="#延續昨日敘事" aria-label="Permalink to &quot;延續昨日敘事&quot;">​</a></h2><p>昨日報告指出：AI capex 與光纖/DCI 需求的結構性新聞持續釋出，光通訊中長期產業邏輯未被破壞。</p><p>今天確認：TrendForce 最新報告再次驗證 CPO/NPO 市場的爆發成長潛力。台灣個股面暫無新重大更新，後續觀察法說與客戶驗證進度。</p><p>查詢時間：2026-06-17 05:00 TST。</p>',43)])])}const b=r(n,[["render",h]]);export{P as __pageData,b as default};
